const express = require('express');
const multer = require('multer');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Step 1: Initial implementation
const storage = multer.diskStorage({
    destination: function (req, file, cb) {
        cb(null, './uploads/');
    },
    filename: function (req, file, cb) {
        cb(null, Date.now() + '_' + file.originalname);
    }
});

const upload = multer({ storage: storage });

app.post('/upload', upload.single('file'), (req, res) => {
    if (!req.file) {
        return res.status(400).send({ message: 'No file uploaded' });
    }

    const allowedExtensions = ['jpg', 'jpeg', 'png', 'gif'];
    const extension = req.file.originalname.split('.').pop().toLowerCase();
    if (allowedExtensions.indexOf(extension) === -1) {
        return res.status(400).send({ message: `Invalid file type. Only ${allowedExtensions.join(', ')} are allowed.` });
    }

    // Step 2-5: Secure implementation
    const maxSize = 10 * 1024 * 1024; // 10MB
    if (req.file.size > maxSize) {
        return res.status(400).send({ message: `File size exceeds the limit of ${maxSize / 1024}KB.` });
    }

    try {
        const fs = require('fs');
        const filePath = req.file.path;
        const fileBuffer = fs.readFileSync(filePath);
        // Process the image/file here
        console.log(fileBuffer.toString());
        res.send({ message: 'File uploaded successfully' });
    } catch (err) {
        return res.status(500).send({ message: err.message });
    }
});

